/**
 * Tier Code lookup — Assurant / GE / Miele.
 *
 * Returns the labor-rate tier for a ticket based on (warranty company,
 * customer ZIP). Data was transcribed from the `US In Home Services Claim
 * Rules.xlsx` workbook the user provided — see specifically:
 *   - "GE Tier Rate List"     → GE_TIER_BY_ZIP
 *   - "Assurant Tier Rate List" → ASSURANT_TIER_BY_ZIP
 *   - "Miele Tier Rate List"  → MIELE_TIER_*_ZIPS
 *
 * All lookups are O(1) (object key lookup or Set membership) and run client
 * side. The resolver returns `null` when the warranty company is outside the
 * eligible set or when the ZIP can't be matched; UI callers render "N/A" in
 * that case.
 */

// ────────────────────────────────────────────────────────────────────────────
// Public types
// ────────────────────────────────────────────────────────────────────────────

export type TierCompany = "GE" | "ASSURANT" | "MIELE";

export interface TierResult {
  /** Resolved company (normalized). */
  company: TierCompany;
  /** Tier code label as it appears in the source sheet (e.g. "MA01", "T200", "Tier 1"). */
  code: string;
  /** Dollar rate associated with this code. */
  rate: number;
  /** Human-readable summary the UI can print directly (e.g. "MA01 ($175.00)"). */
  label: string;
}

// ────────────────────────────────────────────────────────────────────────────
// Company matcher (Requirement 5)
// ────────────────────────────────────────────────────────────────────────────

function normalize(value: string | null | undefined): string {
  return String(value || "")
    .toLowerCase()
    .replace(/[^a-z0-9 ]/g, "")
    .trim();
}

/**
 * Resolve a raw warranty company string + optional account number to one of
 * our eligible tier companies (GE / Assurant / Miele). Returns `null` for
 * anything else.
 *
 * Note: ServicePower hands the SAME servicer credential (`GSL00002`) on
 * every ticket regardless of the actual warranty company, so we can NOT use
 * the account number as a short-circuit — doing so would tag Square Trade
 * / NSA / etc. tickets as Assurant. We rely solely on the warranty company
 * string match. The `accountNo` parameter is kept on the signature for
 * forward compatibility but is intentionally unused today.
 */
export function matchTierCompany(
  rawCompany: string | null | undefined,
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  _accountNo?: string | null,
): TierCompany | null {
  const n = normalize(rawCompany);
  if (!n) return null;
  if (n.includes("assurant")) return "ASSURANT";
  if (n.includes("miele")) return "MIELE";
  // GE matching needs care because "ge" is short and could collide. Require
  // either a whole-word "ge" token or the brand marker "ge appliances".
  // Excluded: anything matching another well-known brand we want to fall
  // through to null (square trade, sppn, nsa, aig, centricity, asurion,
  // home assure, fidelity, etc.).
  if (n.includes("square trade") || n.includes("squaretrade")) return null;
  if (n.includes("sppn") || n.includes("service power")) return null;
  if (n.includes("nsa") || n.includes("national service")) return null;
  if (n.includes("aig")) return null;
  if (n.includes("centricity")) return null;
  if (n.includes("asurion")) return null;
  if (n.includes("home assure") || n.includes("homeassure")) return null;
  if (n.includes("armis")) return null;
  if (n.includes("fidelity")) return null;
  if (n.includes("onpoint") || n.includes("on point")) return null;
  if (/(^|\s)ge($|\s)/.test(n) || n.includes("ge appliances")) return "GE";
  return null;
}


// ────────────────────────────────────────────────────────────────────────────
// ZIP utilities
// ────────────────────────────────────────────────────────────────────────────

/**
 * Extract the leading 5-digit ZIP. Tolerates ZIP+4 (`30024-1234`) and
 * whitespace. Returns `null` if there aren't 5 leading digits.
 */
export function normalizeZip(zip: string | null | undefined): string | null {
  const raw = String(zip || "").trim();
  const m = raw.match(/^(\d{5})/);
  return m ? m[1] : null;
}

