const MIELE_RATES: Record<"BASE" | "T1" | "T2" | "T3", { code: string; rate: number }> = {
  BASE: { code: "Base", rate: 190.0 },
  T1: { code: "Tier 1", rate: 250.0 },
  T2: { code: "Tier 2", rate: 270.0 },
  T3: { code: "Tier 3", rate: 310.0 },
};

const MIELE_TIER_1_SET = new Set<string>(MIELE_TIER_1);
const MIELE_TIER_2_SET = new Set<string>(MIELE_TIER_2);
const MIELE_TIER_3_SET = new Set<string>(MIELE_TIER_3);


// ────────────────────────────────────────────────────────────────────────────
// Resolver (Requirements 1, 7)
// ────────────────────────────────────────────────────────────────────────────

/** Format a TierResult into the standard label printed everywhere. */
export function formatTierLabel(result: TierResult): string {
  return `${result.code} ($${result.rate.toFixed(2)})`;
}

/**
 * Resolve the tier for a (warranty company, customer zip). Optional
 * `accountNo` short-circuits the company match when ServicePower hands us a
 * known billing account number (e.g. Assurant's GSL00002).
 *
 * Returns `null` when:
 *  - the warranty company is outside the eligible set (anything other than
 *    GE, Assurant, Miele),
 *  - the ZIP can't be normalized to 5 digits, or
 *  - the ZIP isn't in GE's / Assurant's tier table (Miele falls back to
 *    Base instead of null since the sheet explicitly defines a Base rate).
 *
 * Never throws — UI callers can render `formatTierLabel` or "N/A" safely.
 */
export function resolveTierCode(
  rawCompany: string | null | undefined,
  rawZip: string | null | undefined,
  accountNo?: string | null,
): TierResult | null {
  const company = matchTierCompany(rawCompany, accountNo);
  if (!company) return null;

  const zip = normalizeZip(rawZip);
  if (!zip) return null;

  if (company === "GE") {
    const hit = GE_TIER_BY_ZIP[zip];
    if (hit) return { company, code: hit.code, rate: hit.rate, label: formatTierLabelRaw(hit.code, hit.rate) };
    // GE fallback per the sheet: "Knoxville $125 base tier" = MA00 / $125.
    const base = GE_RATES.MA00;
    return { company, code: base.code, rate: base.rate, label: formatTierLabelRaw(base.code, base.rate) };
  }

  if (company === "ASSURANT") {
    const hit = ASSURANT_TIER_BY_ZIP[zip];
    if (hit) return { company, code: hit.code, rate: hit.rate, label: formatTierLabelRaw(hit.code, hit.rate) };
    // Assurant sheet note: "Zip code is not under the list must be base rate".
    // The sheet defines a base T200 fee of $170, so we surface that as the
    // base rather than a different code.
    const base = ASSURANT_RATES.T200;
    return { company, code: "Base", rate: base.rate, label: formatTierLabelRaw("Base", base.rate) };
  }

  // MIELE
  if (MIELE_TIER_1_SET.has(zip)) {
    const t = MIELE_RATES.T1;
    return { company, code: t.code, rate: t.rate, label: formatTierLabelRaw(t.code, t.rate) };
  }
  if (MIELE_TIER_2_SET.has(zip)) {
    const t = MIELE_RATES.T2;
    return { company, code: t.code, rate: t.rate, label: formatTierLabelRaw(t.code, t.rate) };
  }
  if (MIELE_TIER_3_SET.has(zip)) {
    const t = MIELE_RATES.T3;
    return { company, code: t.code, rate: t.rate, label: formatTierLabelRaw(t.code, t.rate) };
  }
  const base = MIELE_RATES.BASE;
  return { company, code: base.code, rate: base.rate, label: formatTierLabelRaw(base.code, base.rate) };
}

function formatTierLabelRaw(code: string, rate: number): string {
  return `${code} ($${rate.toFixed(2)})`;
}
